package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testIsNullStringSet_WhenNullStringIsNull() {
        csvFormat = csvFormat.withNullString(null);
        assertFalse(csvFormat.isNullStringSet());
    }

    @Test
    void testIsNullStringSet_WhenNullStringIsNotNull() {
        csvFormat = csvFormat.withNullString("NULL");
        assertTrue(csvFormat.isNullStringSet());
    }
}
